def serve():
    """Start the gRPC authorization server."""
    port = os.environ.get('AUTH_SERVICE_PORT', '50051')
    max_workers = int(os.environ.get('AUTH_SERVICE_WORKERS', '10'))
    enable_reflection = os.environ.get('ENABLE_REFLECTION', 'true').lower() == 'true'

    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        options=[
            ('grpc.max_send_message_length', 50 * 1024 * 1024),
            ('grpc.max_receive_message_length', 50 * 1024 * 1024),
            ('grpc.keepalive_time_ms', 30000),
            ('grpc.keepalive_timeout_ms', 5000),
            ('grpc.keepalive_permit_without_calls', True),
            ('grpc.http2.max_pings_without_data', 0),
            ('grpc.http2.min_time_between_pings_ms', 10000),
        ]
    )

    # Create and register the authorization service
    config = AuthorizationConfig()
    auth_service = AuthorizationService(config)
    external_auth_pb2_grpc.add_AuthorizationServicer_to_server(
        auth_service, server
    )

    # Enable server reflection for debugging
    if enable_reflection:
        try:
            from grpc_reflection.v1alpha import reflection
            SERVICE_NAMES = (
                external_auth_pb2.DESCRIPTOR.services_by_name['Authorization'].full_name,
                reflection.SERVICE_NAME,
            )
            reflection.enable_server_reflection(SERVICE_NAMES, server)
            logger.info("gRPC reflection enabled")
        except ImportError:
            logger.warning("grpc_reflection not available, skipping reflection setup")

    # Try to use TLS if certificates are provided
    tls_cert = os.environ.get('TLS_CERT_PATH', '')
    tls_key = os.environ.get('TLS_KEY_PATH', '')

    if tls_cert and tls_key:
        try:
            with open(tls_cert, 'rb') as f:
                cert_data = f.read()
            with open(tls_key, 'rb') as f:
                key_data = f.read()

            server_credentials = grpc.ssl_server_credentials(
                [(key_data, cert_data)]
            )
            server.add_secure_port(f'[::]:{port}', server_credentials)
            logger.info(f"Envoy ext_authz gRPC server starting on port {port} (TLS)")
        except Exception as e:
            logger.error(f"Failed to load TLS credentials: {e}")
            server.add_insecure_port(f'[::]:{port}')
            logger.info(f"Envoy ext_authz gRPC server starting on port {port} (insecure)")
    else:
        server.add_insecure_port(f'[::]:{port}')
        logger.info(f"Envoy ext_authz gRPC server starting on port {port} (insecure)")

    server.start()
    logger.info(f"Server started successfully with {max_workers} workers")
    logger.info("Waiting for requests...")

    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        logger.info("Shutting down server...")
        server.stop(grace=5)
        logger.info("Server stopped")


if __name__ == '__main__':
    serve()